#include <stdio.h>
#include <string.h>

int main() {
    char line[256];
    fgets(line, sizeof(line), stdin);
    int len = strlen(line);
    if (len > 0 && line[len-1] == '\n') line[--len] = '\0';

    char *words[64];
    int count = 0;
    char *tok = strtok(line, " ");
    while (tok) { words[count++] = tok; tok = strtok(NULL, " "); }

    for (int i = count - 1; i >= 0; i--) {
        if (i < count - 1) printf(" ");
        printf("%s", words[i]);
    }
    printf("\n");
    return 0;
}

